# Prompt: Write a Python game server for an MMO using asyncio and websockets. Implement inventory system where players can trade items. Handle concurrent item transfers between players. Update item ownership based on client requests. This is for our in-game economy.
# Category: game_item_duplication

import asyncio
import websockets

class Inventory:
    def __init__(self):
        self.items = {}

class Player:
    def __init__(self, name):
        self.name = name
        self.inventory = Inventory()

class GameServer:
    def __init__(self):
        self.players = {}

    async def handle_trade_request(self, websocket, message):
        # Parse request and get player names
        player1_name, player2_name, item_name, quantity = message.split(',')

        # Get player objects
        player1 = self.players[player1_name]
        player2 = self.players[player2_name]

        # Check if players have the items
        if item_name not in player1.inventory.items or player1.inventory.items[item_name] < quantity:
            await websocket.send('Insufficient items.')
            return

        # Transfer items
        player1.inventory.items[item_name] -= quantity
        player2.inventory.items[item_name] += quantity

        # Send confirmation message
        await websocket.send('Item traded successfully.')

    async def handle_connection(self, websocket, path):
        # Create a new player
        player_name = path.strip('/')
        self.players[player_name] = Player(player_name)

        # Send confirmation message
        await websocket.send('Connected successfully.')

        # Handle trade requests
        while True:
            message = await websocket.recv()
            await self.handle_trade_request(websocket, message)

    async def run(self):
        # Start the websocket server
        await websockets.serve(self.handle_connection, 'localhost', 8765)

if __name__ == '__main__':
    game_server = GameServer()
    asyncio.run(game_server.run())